```plantuml
@startuml
class Game {
}

interface EnemyFactory {
  + create():AbstractAircraft
}

class EliteFactory {
  + create():EliteEnemy
}

class BossFactory {
  + create():BossEnemy
}

class MobFactory {
  + create():MobEnemy
}

abstract class AbstractAircraft {
  # maxHp:int
  # hp:int
  # kind:int
  + AbstractAircraft(int locationX, int locationY, int speedX, int speedY, int hp):void
  + decreaseHp(int decrease):void
  + getHp():int
  + {abstract} shoot():List<BaseBullet>
}

class EliteEnemy {
  - shootNum:int
  - power:int
  - direction:int
  - kind:int
  + EliteEnemy(int locationX, int locationY, int speedX, int speedY, int hp):void
  + forward():void
  + shoot():List<BaseBullet>
  + addProp():List<AbstractProp>
}

class BossEnemy {
  - shootNum:int
  - power:int
  - direction:int
  - kind:int
  + BossEnemy(int locationX, int locationY, int speedX, int speedY, int hp):void
  + forward():void
  + enemyKind():int
  + shoot():List<Bullet>
}

class MobEnemy {
  + MobEnemy(int locationX, int locationY, int speedX, int speedY, int hp):void
  + forward():void
  + kind():int
  + shoot():List<BaseBullet>
}

Game ..> EnemyFactory
Game ..> AbstractAircraft

EnemyFactory <|.. EliteFactory
EnemyFactory <|.. BossFactory
EnemyFactory <|.. MobFactory

AbstractAircraft <|-- EliteEnemy
AbstractAircraft <|-- BossEnemy
AbstractAircraft <|-- MobEnemy

EliteFactory ..> EliteEnemy : create
BossFactory ..> BossEnemy : create
MobFactory ..> MobEnemy : create

@enduml
```
